question:
What will be the output of the following code?

```cpp
#include <iostream>
using namespace std;
int main() {
    int x = 5;
    cout << x++ << endl;
    cout << ++x << endl;
}
```

What will be the output of the following code?

```cpp
#include <iostream>
using namespace std;
int main() {
    int arr[3] = {10, 20, 30};
    cout << *(arr + 1);
}
```

What will be the output of the following code?

```cpp
#include <iostream>
using namespace std;
class Base {
public:
    virtual void show() { cout << "Base"; }
};
class Derived : public Base {
public:
    void show() { cout << "Derived"; }
};
int main() {
    Base* b = new Derived();
    b->show();
}
```
